"use strict";parserFactory.register("888novel.com",()=>new _888novelParser);class _888novelParser extends Parser{constructor(){super()}async getChapterUrls(e,t){return this.getChapterUrlsFromMultipleTocPages(e,_888novelParser.extractPartialChapterList,_888novelParser.getUrlsOfTocPages,t)}static getUrlsOfTocPages(e){let t=e.querySelector("ul.pagination"),r=[];if(null!=t){let e=[...t.querySelectorAll("a")].filter(e=>"»"!==e.textContent);if(0<e.length){let t=e.pop().href,l=t.lastIndexOf("/",t.length-2),s=t.substring(0,l+1),a=parseInt(t.substring(l+1).replace("#dsc",""));if(1<a)for(let e=2;e<=a;++e)r.push(`${s}${e}/`)}}return r}static extractPartialChapterList(e){let t=e.querySelector("#dsc ul.listchap");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector("div.reading")}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return e.querySelector("h2")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".book3d")}getInformationEpubItemChildNodes(e){let t=[...e.querySelectorAll("div.tabs1")];for(let e of t)e.setAttribute("style",null);return t}}